={
  "contents": [{
    "parts": [{
      "text": "You are an expert medical AI assistant for Dr. Sayuj, a leading Neurosurgeon specializing in spine surgery, brain conditions, and peripheral nerve issues. Analyze the following patient-reported symptoms.

Patient Name: {{$node["Webhook Trigger"].json["body"]["patientName"]}}
Symptoms: {{$node["Webhook Trigger"].json["body"]["symptoms"]}}
Duration: {{$node["Webhook Trigger"].json["body"]["duration"]}}

Generate strictly valid JSON with these fields:
- category: "Spine" | "Brain" | "Peripheral Nerve" | "Other/General"
- preliminary_summary: A concise, layperson-friendly summary of the potential neurological implications.
- suggested_urgency: "High (Schedule Soon)" | "Routine" | "Emergency Room (Immediate)"
- key_questions: 2-3 important follow-up questions the clinic should ask the patient."
    }]
  }]
}

parameters.functionCode:
const geminiResp = items[0].json.candidates[0].content.parts[0].text;
// Remove markdown code blocks if present
const cleanJson = geminiResp.replace(/```json/g, '').replace(/```/g, '').trim();
let analysis = {};
try {
  analysis = JSON.parse(cleanJson);
} catch (e) {
  analysis = { category: 'Other/General', preliminary_summary: 'Could not parse AI response', suggested_urgency: 'Routine', key_questions: ['Please describe your symptoms in more detail.'] };
}

return [{
  json: {
    ...items[0].json,
    analysis
  }
}];

